using System.Text.Json;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/version", Name = "App Version",
        MimeType = "text/plain"),
     Description("Returns the application version string.")]
    public static string GetVersion() => "1.0.0";
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Checks whether a specific feature flag is enabled.")]
    public static string CheckFeatureFlag(
        [Description("The name of the feature flag to check")] string flagName)
    {
        var flags = new Dictionary<string, bool>(StringComparer.OrdinalIgnoreCase)
        {
            ["DarkMode"] = true,
            ["BetaAccess"] = false,
            ["Notifications"] = true
        };

        return flags.TryGetValue(flagName, out var enabled)
            ? $"Feature '{flagName}' is {(enabled ? "enabled" : "disabled")}."
            : $"Feature '{flagName}' not found.";
    }
}

